evaluators.evaluation_logic:
const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const savedPrograms = JSON.parse(localStorage.getItem('saved_programs') || '[]');

// Find qualifying programs by criteria
const qualifyingProgramIds = programs
  .filter(p => {
    if (!p || p.status !== 'paying') return false;
    const methods = Array.isArray(p.payment_methods) ? p.payment_methods : [];
    if (!methods.includes('bitcoin')) return false;
    if (typeof p.daily_roi_percent !== 'number' || p.daily_roi_percent < 3) return false;
    if (typeof p.min_deposit_usd !== 'number' || p.min_deposit_usd > 20) return false;
    return true;
  })
  .map(p => p.id);

// Watchlisted programs that meet all criteria
const qualifyingWatchlisted = savedPrograms.filter(sp => {
  if (!sp || sp.save_type !== 'watchlist') return false;
  return qualifyingProgramIds.includes(sp.program_id);
});

const qualifyingCount = qualifyingWatchlisted.length;

// CP1-3: number of qualifying watchlisted programs (only qualifying ones count)
const weights = [0.3, 0.3, 0.4];
[1, 2, 3].forEach((n, idx) => {
  checkpoints.push({
    passed: qualifyingCount >= n,
    weight: weights[idx]
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const listingStates = JSON.parse(localStorage.getItem('program_listing_filter_states') || '[]');
const comparedObj = JSON.parse(localStorage.getItem('task2_comparedProgramIds') || 'null');
const bookmarkedId = localStorage.getItem('task2_bookmarkedProgramId') || '';

const comparedIds = comparedObj && Array.isArray(comparedObj.comparedProgramIds)
  ? comparedObj.comparedProgramIds
  : [];

// Qualifying programs for this task: paying and running 10–60 days
const qualifyingPrograms = programs.filter(p => {
  if (!p || p.status !== 'paying') return false;
  const days = typeof p.running_days === 'number' ? p.running_days : null;
  return days !== null && days >= 10 && days <= 60;
});
const qualifyingIds = qualifyingPrograms.map(p => p.id);

// Programs the user actually compared that qualify
const comparedQualifyingIds = comparedIds.filter(id => qualifyingIds.includes(id));

// Find the best (highest 30-day total return) among compared qualifying
let bestComparedProgram = null;
comparedQualifyingIds.forEach(id => {
  const p = programs.find(pr => pr && pr.id === id);
  if (!p || typeof p.total_return_30d_percent !== 'number') return;
  if (!bestComparedProgram || p.total_return_30d_percent > bestComparedProgram.total_return_30d_percent) {
    bestComparedProgram = p;
  }
});

const bookmarkedProgram = programs.find(p => p && p.id === bookmarkedId) || null;

// Optional filter correctness: last applied listing state
let lastState = null;
if (Array.isArray(listingStates) && listingStates.length > 0) {
  lastState = listingStates.find(s => s && s.id === 'listing_state_1') || listingStates[listingStates.length - 1];
}

const filterCorrect = !!lastState && Array.isArray(lastState.status_filter) &&
  lastState.status_filter.length === 1 &&
  lastState.status_filter[0] === 'paying' &&
  typeof lastState.min_running_days === 'number' && lastState.min_running_days >= 10 &&
  typeof lastState.max_running_days === 'number' && lastState.max_running_days <= 60;

// CP1 (0.30): User applied a listing filter that matches the task criteria (paying, 10–60 days)
checkpoints.push({
  passed: filterCorrect,
  weight: 0.30
});

// CP2 (0.30): User compared at least two qualifying programs (paying, 10–60 days)
checkpoints.push({
  passed: comparedQualifyingIds.length >= 2,
  weight: 0.30
});

// CP3 (0.40): User bookmarked the highest 30-day return program among the compared qualifying ones
const bookmarkIsBestCompared = !!(bookmarkedProgram && bestComparedProgram &&
  bookmarkedProgram.id === bestComparedProgram.id &&
  comparedQualifyingIds.includes(bookmarkedProgram.id) &&
  bookmarkedProgram.status === 'paying' &&
  typeof bookmarkedProgram.running_days === 'number' &&
  bookmarkedProgram.running_days >= 10 &&
  bookmarkedProgram.running_days <= 60);

checkpoints.push({
  passed: bookmarkIsBestCompared,
  weight: 0.40
});

return checkPointsTotal = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const comments = JSON.parse(localStorage.getItem('program_comments') || '[]');

// Programs that meet the 300%/30d and paying criteria
const qualifyingProgramIds = programs
  .filter(p => p && p.status === 'paying' && typeof p.total_return_30d_percent === 'number' && p.total_return_30d_percent >= 300)
  .map(p => p.id);

// Reviews for those programs with exactly 4 stars
const candidateComments = comments.filter(c => {
  if (!c || !qualifyingProgramIds.includes(c.program_id)) return false;
  if (!c.is_review) return false;
  const stars = typeof c.rating_stars === 'number' ? c.rating_stars : Number(c.rating_stars);
  return stars === 4;
});

let targetComment = null;
if (candidateComments.length > 0) {
  targetComment = candidateComments.reduce((latest, c) => {
    if (!latest) return c;
    const tLatest = Date.parse(latest.created_at || 0);
    const tC = Date.parse(c.created_at || 0);
    return tC > tLatest ? c : latest;
  }, null);
}

// Helper to count sentences similar to BusinessLogic._validateReviewContent
const countSentences = (text) => {
  if (!text) return 0;
  return text
    .split(/[.!?]+/)
    .map(s => s.trim())
    .filter(s => s.length > 0).length;
};

const hasPositivePoint = (body) => {
  if (!body) return false;
  const b = body.toLowerCase();
  return /good|great|nice|love|excellent|paying|payout|withdrawal processed|no issues|support.*(responsive|fast|quick)/i.test(body);
};

const hasRiskConcern = (body) => {
  if (!body) return false;
  const b = body.toLowerCase();
  return /risk|high risk|scam|unsustainable|insane|too good to be true|lose money|loss|gamble|doubt|can't afford to lose/i.test(body);
};

// CP1 (0.40): At least one qualifying 4-star review exists on a ≥300%/30d paying program
const cp1Passed = !!targetComment;
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.30): That review comment has at least two sentences
let cp2Passed = false;
if (targetComment && typeof targetComment.body === 'string') {
  cp2Passed = countSentences(targetComment.body) >= 2;
}
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.30): That review mentions both a positive point and a risk concern
let cp3Passed = false;
if (targetComment && typeof targetComment.body === 'string') {
  cp3Passed = hasPositivePoint(targetComment.body) && hasRiskConcern(targetComment.body);
}
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const categories = JSON.parse(localStorage.getItem('forum_categories') || '[]');
const threads = JSON.parse(localStorage.getItem('forum_threads') || '[]');
const posts = JSON.parse(localStorage.getItem('forum_posts') || '[]');

const catMap = new Map();
(Array.isArray(categories) ? categories : []).forEach(c => { if (c && c.id) catMap.set(c.id, c); });

// Threads created by the local user in a New HYIPs category
const localNewHyipThreads = (Array.isArray(threads) ? threads : []).filter(t => {
  if (!t || t.author_username !== 'local_user') return false;
  const cat = catMap.get(t.category_id);
  return cat && cat.category_type === 'new_hyips';
});

// Attach first post bodies
const threadInfos = localNewHyipThreads.map(t => {
  const firstPost = (Array.isArray(posts) ? posts : []).find(p => p && p.thread_id === t.id && p.is_first_post);
  return { thread: t, firstPost };
});

// Helper: does body mention a 5% daily plan?
const mentionsFivePercentDaily = (body) => {
  if (!body) return false;
  return /5\s*%\s*daily/i.test(body);
};

// Evaluate threads
let anyFiveDailyThread = false;
let anyWithAllFields = false;

threadInfos.forEach(info => {
  const body = info.firstPost && typeof info.firstPost.body === 'string' ? info.firstPost.body : '';
  if (!mentionsFivePercentDaily(body)) return;
  anyFiveDailyThread = true;
  const hasStartDate = body.includes('Start Date:');
  const hasMinDeposit = body.includes('Minimum Deposit:');
  const hasPaymentMethods = body.includes('Payment Methods:');
  const hasPlan = body.includes('Plan:');
  if (hasStartDate && hasMinDeposit && hasPaymentMethods && hasPlan) {
    anyWithAllFields = true;
  }
});

// CP1 (0.40): Created at least one New HYIPs thread as local_user that clearly mentions a 5% daily plan
checkpoints.push({
  passed: anyFiveDailyThread,
  weight: 0.40
});

// CP2 (0.60): In such a thread, the first post includes Start Date, Minimum Deposit, Payment Methods, and Plan labels
checkpoints.push({
  passed: anyWithAllFields,
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const savedPrograms = JSON.parse(localStorage.getItem('saved_programs') || '[]');
const accountSettingsArr = JSON.parse(localStorage.getItem('account_settings') || '[]');
const settings = Array.isArray(accountSettingsArr) && accountSettingsArr.length > 0 ? accountSettingsArr[0] : null;

// Qualifying problematic programs
const qualifyingProblematicIds = programs
  .filter(p => {
    if (!p) return false;
    if (!(p.status === 'scam' || p.status === 'not_paying')) return false;
    if (typeof p.min_deposit_usd !== 'number' || p.min_deposit_usd < 100) return false;
    if (typeof p.running_days !== 'number' || p.running_days >= 15) return false;
    return true;
  })
  .map(p => p.id);

// Blacklisted programs among those
const blacklistedQualifying = savedPrograms.filter(sp => {
  if (!sp || sp.save_type !== 'blacklist') return false;
  return qualifyingProblematicIds.includes(sp.program_id);
});

const qualifyingBlacklistCount = blacklistedQualifying.length;

const scamAlertsEnabled = !!(settings && settings.notifications_scam_alerts_in_site === true);

// CP1 (0.40): At least one qualifying problematic program has been blacklisted
checkpoints.push({
  passed: qualifyingBlacklistCount >= 1,
  weight: 0.40
});

// CP2 (0.40): At least two qualifying problematic programs have been blacklisted
checkpoints.push({
  passed: qualifyingBlacklistCount >= 2,
  weight: 0.40
});

// CP3 (0.20): Scam alerts subscription enabled AND at least two qualifying programs blacklisted
checkpoints.push({
  passed: scamAlertsEnabled && qualifyingBlacklistCount >= 2,
  weight: 0.20
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const polls = JSON.parse(localStorage.getItem('program_polls') || '[]');
const options = JSON.parse(localStorage.getItem('poll_options') || '[]');

// Qualifying programs: paying, running_days <= 7, payout_rating_value === 5.0, has_active_poll
const qualifyingPrograms = programs.filter(p => {
  if (!p || p.status !== 'paying') return false;
  const days = typeof p.running_days === 'number' ? p.running_days : null;
  if (days === null || days > 7 || days < 0) return false;
  if (typeof p.payout_rating_value !== 'number' || p.payout_rating_value < 5.0) return false;
  if (!p.has_active_poll) return false;
  return true;
});

let cautiousVoteCast = false;

qualifyingPrograms.forEach(p => {
  const poll = polls.find(pl => pl && pl.program_id === p.id);
  if (!poll || !poll.has_user_voted || !poll.user_selected_option_id) return;
  const pollOptions = options.filter(o => o && o.poll_id === poll.id);
  const cautiousOption = pollOptions.find(o => o && /no, i will stay away/i.test(o.text || ''));
  if (!cautiousOption) return;
  if (poll.user_selected_option_id === cautiousOption.id) {
    cautiousVoteCast = true;
  }
});

// Single checkpoint: user must have cast the cautious non-investing vote on a qualifying program's poll
checkpoints.push({
  passed: cautiousVoteCast,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accountSettingsArr = JSON.parse(localStorage.getItem('account_settings') || '[]');
const settings = Array.isArray(accountSettingsArr) && accountSettingsArr.length > 0 ? accountSettingsArr[0] : null;

if (!settings) {
  return 0.0;
}

// CP1 (0.20): Default currency set to USD
const cp1Passed = typeof settings.default_currency === 'string' && settings.default_currency.toLowerCase() === 'usd';
checkpoints.push({ passed: cp1Passed, weight: 0.20 });

// CP2 (0.20): Minimum daily ROI filter is at least 1.5%
const roi = typeof settings.dashboard_min_daily_roi_percent === 'number'
  ? settings.dashboard_min_daily_roi_percent
  : Number(settings.dashboard_min_daily_roi_percent);
const cp2Passed = !isNaN(roi) && roi >= 1.5;
checkpoints.push({ passed: cp2Passed, weight: 0.20 });

// CP3 (0.20): Status filter is set to only 'paying' (active programs only)
const statusFilter = Array.isArray(settings.dashboard_status_filter) ? settings.dashboard_status_filter : [];
const cp3Passed = statusFilter.length === 1 && statusFilter[0] === 'paying';
checkpoints.push({ passed: cp3Passed, weight: 0.20 });

// CP4 (0.20): Closed programs are hidden
const cp4Passed = settings.dashboard_show_closed_programs === false;
checkpoints.push({ passed: cp4Passed, weight: 0.20 });

// CP5 (0.20): In-site notifications for watchlist risk/status changes enabled
const cp5Passed = settings.notifications_watchlist_risk_in_site === true;
checkpoints.push({ passed: cp5Passed, weight: 0.20 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const messages = JSON.parse(localStorage.getItem('private_messages') || '[]');
const comments = JSON.parse(localStorage.getItem('program_comments') || '[]');

// Build index of latest comment per program
const latestCommentByProgram = new Map();
(Array.isArray(comments) ? comments : []).forEach(c => {
  if (!c || !c.program_id) return;
  const existing = latestCommentByProgram.get(c.program_id);
  const tExisting = existing ? Date.parse(existing.created_at || 0) : -Infinity;
  const tCurrent = Date.parse(c.created_at || 0);
  if (!existing || tCurrent > tExisting) {
    latestCommentByProgram.set(c.program_id, c);
  }
});

const subjectMatch = (subject) => {
  if (!subject) return false;
  return subject.toLowerCase().includes('question about your hyip payout experience');
};

const bodyAsksQuestions = (body) => {
  if (!body) return false;
  const questionCount = (body.match(/\?/g) || []).length;
  if (questionCount < 2) return false;
  const b = body.toLowerCase();
  const mentionsPayout = /payout|payment|withdrawal/i.test(b);
  const mentionsSpeed = /speed|how long|how fast|time|duration/i.test(b);
  const mentionsDeposit = /deposit|how much.*(invest|deposit)|size of.*(deposit|investment)|amount.*you (put in|invested)/i.test(b);
  return mentionsPayout && mentionsSpeed && mentionsDeposit;
};

let hasQualifyingMessage = false;

(Array.isArray(messages) ? messages : []).forEach(m => {
  if (!m) return;
  if (!subjectMatch(m.subject)) return;
  if (!bodyAsksQuestions(m.body)) return;
  if (!m.related_comment_id) return;
  const comment = comments.find(c => c && c.id === m.related_comment_id);
  if (!comment || !comment.program_id) return;
  const latestForProgram = latestCommentByProgram.get(comment.program_id);
  if (!latestForProgram) return;
  // Check that the message is tied to the latest comment for that program
  if (latestForProgram.id === comment.id) {
    hasQualifyingMessage = true;
  }
});

// Single checkpoint: private message meets subject/body requirements and targets latest commenter
checkpoints.push({
  passed: hasQualifyingMessage,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
